import pandas as pdimport numpy as npimport seaborn as snsimport matplotlib.pyplot as pltimport os# --- LOAD DATA ----------------------------------------------------------------trainings = pd.read_csv('data/processed/running_clean.csv')# --- PLOT SETTINGS ------------------------------------------------------------PRIMARY   = '#30D158'SECONDARY = '#34C759'ACCENT    = '#FF375F'sns.set_theme(style='whitegrid')plt.style.use('seaborn-v0_8-whitegrid')os.makedirs('plots', exist_ok=True)# --- TRAINING VOLUME ----------------------------------------------------------# Sessions per yearsessions_per_year = trainings.groupby('year').size().reset_index(name='sessions')plt.figure(figsize=(10, 5))sns.barplot(data=sessions_per_year, x='year', y='sessions', color=PRIMARY)plt.title('Running Sessions per Year', fontsize=14)plt.xlabel('Year')plt.ylabel('Number of Sessions')plt.tight_layout()plt.savefig('plots/01_sessions_per_year.png', dpi=150)plt.show()# Total kilometers per yearkilometers_per_year = trainings.groupby('year')['distance_km'].sum().reset_index(name='kilometers')plt.figure(figsize=(10, 5))sns.barplot(data=kilometers_per_year, x='year', y='kilometers', color=PRIMARY)plt.title('Total Kilometers per Year', fontsize=14)plt.xlabel('Year')plt.ylabel('Total Distance (km)')plt.tight_layout()plt.savefig('plots/02_kilometers_per_year.png', dpi=150)plt.show()# Training sessions heatmap (year vs month)heatmap_data  = trainings.groupby(['year', 'month']).size().reset_index(name='sessions')heatmap_pivot = heatmap_data.pivot(index='year', columns='month', values='sessions').fillna(0)month_order   = ['January', 'February', 'March', 'April', 'May', 'June',                 'July', 'August', 'September', 'October', 'November', 'December']heatmap_pivot = heatmap_pivot.reindex(columns=month_order)plt.figure(figsize=(14, 6))sns.heatmap(heatmap_pivot, cmap='Greens', linewidths=0.5,            annot=True, fmt='.0f', cbar_kws={'label': 'Sessions'})plt.title('Training Sessions Heatmap (Year vs Month)', fontsize=14)plt.xlabel('Month')plt.ylabel('Year')plt.tight_layout()plt.savefig('plots/03_sessions_heatmap.png', dpi=150)plt.show()# Distance distributionplt.figure(figsize=(10, 5))sns.histplot(data=trainings, x='distance_km', bins=20, color=PRIMARY)plt.title('Distribution of Running Distances', fontsize=14)plt.xlabel('Distance (km)')plt.ylabel('Number of Sessions')plt.xticks(range(0, 22, 1))plt.tight_layout()plt.savefig('plots/04_distance_distribution.png', dpi=150)plt.show()# Cumulative kilometers over timetrainings_sorted              = trainings.sort_values('datetime')trainings_sorted['datetime']  = pd.to_datetime(trainings_sorted['datetime'])trainings_sorted['cumulative_km'] = trainings_sorted['distance_km'].cumsum()fig, ax = plt.subplots(figsize=(12, 5))ax.plot(trainings_sorted['datetime'], trainings_sorted['cumulative_km'], color=PRIMARY, linewidth=2)ax.xaxis.set_major_locator(plt.matplotlib.dates.YearLocator())ax.xaxis.set_major_formatter(plt.matplotlib.dates.DateFormatter('%Y'))plt.title('Cumulative Kilometers Over Time', fontsize=14)plt.xlabel('Year')plt.ylabel('Total Kilometers (km)')plt.grid(axis='y')plt.tight_layout()plt.savefig('plots/05_cumulative_km.png', dpi=150)plt.show()# --- PERFORMANCE --------------------------------------------------------------# Pace distribution per yearplt.figure(figsize=(10, 5))sns.boxplot(data=trainings, x='year', y='pace_min_km', color=PRIMARY)plt.title('Pace Distribution per Year', fontsize=14)plt.xlabel('Year')plt.ylabel('Pace (min/km)')plt.tight_layout()plt.savefig('plots/06_pace_per_year.png', dpi=150)plt.show()# Distance vs Paceplt.figure(figsize=(10, 5))sns.scatterplot(data=trainings, x='distance_km', y='pace_min_km', hue='year', palette='tab10')plt.title('Distance vs Pace', fontsize=14)plt.xlabel('Distance (km)')plt.ylabel('Pace (min/km)')plt.tight_layout()plt.savefig('plots/07_distance_vs_pace.png', dpi=150)plt.show()# Duration vs Calories Burnedplt.figure(figsize=(10, 5))sns.scatterplot(data=trainings, x='duration_min', y='active_calories', color=PRIMARY, alpha=0.6)sns.regplot(data=trainings, x='duration_min', y='active_calories',            scatter=False, color=ACCENT, line_kws={'linewidth': 2})plt.title('Duration vs Calories Burned', fontsize=14)plt.xlabel('Duration (min)')plt.ylabel('Active Calories (kcal)')plt.tight_layout()plt.savefig('plots/08_duration_vs_calories.png', dpi=150)plt.show()# Elevation vs Paceplt.figure(figsize=(10, 5))sns.scatterplot(data=trainings, x='elevation_m', y='pace_min_km', color=PRIMARY, alpha=0.6)sns.regplot(data=trainings, x='elevation_m', y='pace_min_km',            scatter=False, color=ACCENT, line_kws={'linewidth': 2})plt.title('Elevation vs Pace', fontsize=14)plt.xlabel('Elevation (m)')plt.ylabel('Pace (min/km)')plt.tight_layout()plt.savefig('plots/09_elevation_vs_pace.png', dpi=150)plt.show()# --- TRAINING PATTERNS --------------------------------------------------------# Average distance per yearavg_distance_per_year = trainings.groupby('year')['distance_km'].mean().reset_index(name='avg_distance')plt.figure(figsize=(10, 5))sns.barplot(data=avg_distance_per_year, x='year', y='avg_distance', color=PRIMARY)plt.title('Average Distance per Year', fontsize=14)plt.xlabel('Year')plt.ylabel('Average Distance (km)')plt.tight_layout()plt.savefig('plots/10_avg_distance_per_year.png', dpi=150)plt.show()# Sessions per weekdaysessions_per_weekday = trainings.groupby('day_of_week').size().reset_index(name='sessions')weekday_order        = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday']plt.figure(figsize=(10, 5))sns.barplot(data=sessions_per_weekday, x='day_of_week', y='sessions', color=PRIMARY, order=weekday_order)plt.title('Running Sessions per Weekday', fontsize=14)plt.xlabel('Weekday')plt.ylabel('Number of Sessions')plt.tight_layout()plt.savefig('plots/11_sessions_per_weekday.png', dpi=150)plt.show()# Sessions per time of daysessions_per_daytime = trainings.groupby('time_of_day').size().reset_index(name='sessions')daytime_order        = ['morning', 'afternoon', 'evening']plt.figure(figsize=(10, 5))sns.barplot(data=sessions_per_daytime, x='time_of_day', y='sessions', color=PRIMARY, order=daytime_order)plt.title('Running Sessions per Time of Day', fontsize=14)plt.xlabel('Time of Day')plt.ylabel('Number of Sessions')plt.tight_layout()plt.savefig('plots/12_sessions_per_time_of_day.png', dpi=150)plt.show()# --- HEART RATE & CONDITIONS --------------------------------------------------trainings_hr = trainings[trainings['hr_available'] == 'with_hr']# Distance vs Average Heart Rateplt.figure(figsize=(10, 5))sns.scatterplot(data=trainings_hr, x='distance_km', y='avg_heart_rate', hue='year', palette='tab10')plt.title('Distance vs Average Heart Rate', fontsize=14)plt.xlabel('Distance (km)')plt.ylabel('Average Heart Rate (bpm)')plt.tight_layout()plt.savefig('plots/13_distance_vs_heart_rate.png', dpi=150)plt.show()# Pace vs Average Heart Rateplt.figure(figsize=(10, 5))sns.scatterplot(data=trainings_hr, x='pace_min_km', y='avg_heart_rate', hue='year', palette='tab10')plt.title('Pace vs Average Heart Rate', fontsize=14)plt.xlabel('Pace (min/km)')plt.ylabel('Average Heart Rate (bpm)')plt.tight_layout()plt.savefig('plots/14_pace_vs_heart_rate.png', dpi=150)plt.show()# Feature correlation matrixnumeric_cols = ['duration_min', 'distance_km', 'active_calories',                'avg_heart_rate', 'pace_min_km', 'elevation_m',                'num_pauses', 'pause_duration_min', 'temperature_c', 'humidity_pct']correlation_matrix = trainings[numeric_cols].corr()plt.figure(figsize=(12, 8))sns.heatmap(correlation_matrix, annot=True, fmt='.2f',            cmap='RdYlGn', center=0, linewidths=0.5)plt.title('Feature Correlation Matrix', fontsize=14)plt.tight_layout()plt.savefig('plots/15_correlation_matrix.png', dpi=150)plt.show()